if (usesPortal) {
  const imports = root.find(j.ImportDeclaration, {
    source: { value: "@chakra-ui/react" },
  })
  if (imports.size() > 0) {
    imports.forEach((imp) => {
      const specs = imp.node.specifiers || []
      const hasPortal = specs.some(
        (s) => s.type === "ImportSpecifier" && s.imported.name === "Portal",
      )
      if (!hasPortal) {
        specs.push(j.importSpecifier(j.identifier("Portal")))
        imp.node.specifiers = specs
      }
    })
  } else {
    root
      .get()
      .node.program.body.unshift(
        j.importDeclaration(
          [j.importSpecifier(j.identifier("Portal"))],
          j.stringLiteral("@chakra-ui/react"),
        ),
      )
  }
}

root
    .find(j.ImportDeclaration, {
      source: { value: "@chakra-ui/next-js" },
    })
    .forEach((path) => {
      path.node.specifiers?.forEach((spec) => {
        if (spec.type === "ImportSpecifier" && spec.local) {
          const importedName = spec.imported.name
          const localName = spec.local.name

          if (importedName === "Link" || importedName === "NextLink") {
            nextJsLinkNames.add(localName as string)
            needsChakraLink = true
          } else if (importedName === "Image" || importedName === "NextImage") {
            nextJsImageNames.add(localName as string)
            needsBox = true
          }
        }
      })
      j(path).remove()
      hasChanges = true
    })

